import{_ as c,o as a,c as o,a3 as t}from"./chunks/framework.aYYe0dfI.js";const u=JSON.parse('{"title":"Module extract:cache","description":"extract:cache 模块是 clore::extract 中负责提取结果缓存的持久化与失效管理子系统。它提供了一组正交的公开操作：通过 build_cache_key 和 build_compile_signature 生成标准化的缓存键与编译签名；利用 capture_dependency_snapshot 和 dependencies_changed 捕获当前依赖状态并判断是否过期；以 load_extract_cache / save_extract_cache 和 load_clice_cache / save_clice_cache 分别支持简单的整数值缓存和完整的 Clice 工作区缓存数据的存储与加载。此外，hash_file 用于计算文件内容的哈希值以支撑依赖追踪，split_cache_key 可将组合键解析为组成部分供外部检查。这些函数共同构成了一个既可独立使用又可组合的缓存工具集，调用者需自行处理返回的 CacheError 以保证缓存一致性。","frontmatter":{"title":"Module extract:cache","description":"extract:cache 模块是 clore::extract 中负责提取结果缓存的持久化与失效管理子系统。它提供了一组正交的公开操作：通过 build_cache_key 和 build_compile_signature 生成标准化的缓存键与编译签名；利用 capture_dependency_snapshot 和 dependencies_changed 捕获当前依赖状态并判断是否过期；以 load_extract_cache / save_extract_cache 和 load_clice_cache / save_clice_cache 分别支持简单的整数值缓存和完整的 Clice 工作区缓存数据的存储与加载。此外，hash_file 用于计算文件内容的哈希值以支撑依赖追踪，split_cache_key 可将组合键解析为组成部分供外部检查。这些函数共同构成了一个既可独立使用又可组合的缓存工具集，调用者需自行处理返回的 CacheError 以保证缓存一致性。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/extract/cache.md","filePath":"zh/clore/modules/extract/cache.md"}'),r={name:"zh/clore/modules/extract/cache.md"};function d(i,e,l,s,h,n){return a(),o("div",null,[...e[0]||(e[0]=[t("",207)])])}const m=c(r,[["render",d]]);export{u as __pageData,m as default};
